import React, { useState, useRef } from 'react';
import { GeminiService } from '../services/geminiService';
import { ExtractionResult } from '../types';
import { ICONS } from '../constants';

interface FileUploadProps {
  onDataExtracted: (result: ExtractionResult) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataExtracted }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const gemini = new GeminiService();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError(null);

    try {
      const reader = new FileReader();

      if (file.type.startsWith('image/')) {
        reader.onload = async () => {
          const base64 = (reader.result as string).split(',')[1];
          const result = await gemini.extractFromImage(base64, file.type);
          onDataExtracted(result);
          setIsUploading(false);
        };
        reader.readAsDataURL(file);
      } else if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls') || file.name.endsWith('.csv')) {
        // Simple Excel reading using standard libraries if available, 
        // otherwise we use a generic text reader to feed Gemini.
        reader.onload = async () => {
          // If we had the library, we'd parse it. For now, let's treat it as text data extraction attempt
          // Or we can assume the user provides a format Gemini can "see" through a text conversion.
          const arrayBuffer = reader.result as ArrayBuffer;
          const workbook = (window as any).XLSX.read(arrayBuffer, { type: 'array' });
          const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
          const json = (window as any).XLSX.utils.sheet_to_json(firstSheet);
          const result = await gemini.extractFromText(JSON.stringify(json));
          onDataExtracted(result);
          setIsUploading(false);
        };
        reader.readAsArrayBuffer(file);
      } else {
        // Fallback or generic text extraction (like for PDF if converted)
        setError("Please upload an image or Excel file.");
        setIsUploading(false);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to extract data. Please try a clearer document.");
      setIsUploading(false);
    }
  };

  return (
    <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 transition-all hover:border-indigo-300">
      <div className="flex flex-col items-center justify-center text-center space-y-4">
        <div className={`w-16 h-16 rounded-full flex items-center justify-center ${isUploading ? 'bg-indigo-100 text-indigo-600 animate-pulse' : 'bg-slate-100 text-slate-400'}`}>
          <ICONS.Upload />
        </div>
        <div>
          <h3 className="text-lg font-bold text-slate-800">Upload Financial Statement</h3>
          <p className="text-slate-500 max-w-sm mt-1">
            Drag and drop your Excel (.xlsx) or Image (PNG, JPG) statement. Gemini AI will automatically extract the model.
          </p>
        </div>
        <input
          type="file"
          className="hidden"
          ref={fileInputRef}
          onChange={handleFileChange}
          accept="image/*, .xlsx, .xls, .csv"
        />
        <button
          disabled={isUploading}
          onClick={() => fileInputRef.current?.click()}
          className={`px-6 py-2.5 rounded-xl font-semibold transition-all shadow-md ${
            isUploading 
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
              : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
          }`}
        >
          {isUploading ? 'Processing with AI...' : 'Choose File'}
        </button>
        {error && <p className="text-red-500 text-sm font-medium">{error}</p>}
      </div>
    </div>
  );
};

export default FileUpload;

import React from 'react';
import { FinancialStatement } from '../types';

interface FinancialTableProps {
  data: FinancialStatement['data'];
  onUpdate: (field: keyof FinancialStatement['data'], value: number) => void;
}

const FinancialTable: React.FC<FinancialTableProps> = ({ data, onUpdate }) => {
  const fields: { key: keyof FinancialStatement['data']; label: string; group: string }[] = [
    { key: 'revenue', label: 'Total Revenue', group: 'Income Statement' },
    { key: 'cogs', label: 'COGS', group: 'Income Statement' },
    { key: 'operatingExpenses', label: 'Op. Expenses', group: 'Income Statement' },
    { key: 'ebitda', label: 'EBITDA', group: 'Income Statement' },
    { key: 'interestExpense', label: 'Interest Expense', group: 'Income Statement' },
    { key: 'netIncome', label: 'Net Income', group: 'Income Statement' },
    { key: 'currentAssets', label: 'Current Assets', group: 'Balance Sheet' },
    { key: 'currentLiabilities', label: 'Current Liabilities', group: 'Balance Sheet' },
    { key: 'totalDebt', label: 'Total Debt', group: 'Balance Sheet' },
    { key: 'totalAssets', label: 'Total Assets', group: 'Balance Sheet' },
    { key: 'equity', label: 'Total Equity', group: 'Balance Sheet' },
  ];

  const grouped = fields.reduce((acc, field) => {
    if (!acc[field.group]) acc[field.group] = [];
    acc[field.group].push(field);
    return acc;
  }, {} as Record<string, typeof fields>);

  const formatCurrency = (val: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(val);

  return (
    <div className="space-y-6">
      {Object.entries(grouped).map(([group, groupFields]) => (
        <div key={group} className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
          <div className="bg-slate-50 px-6 py-3 border-b border-slate-200">
            <h4 className="text-sm font-bold text-slate-700 uppercase tracking-wider">{group}</h4>
          </div>
          <div className="divide-y divide-slate-100">
            {groupFields.map((field) => (
              <div key={field.key} className="flex items-center justify-between px-6 py-4 hover:bg-slate-50/50 transition-colors">
                <span className="text-slate-600 font-medium">{field.label}</span>
                <div className="flex items-center gap-4">
                  <span className="text-xs text-slate-400 font-mono">{formatCurrency(data[field.key])}</span>
                  <input
                    type="number"
                    value={data[field.key]}
                    onChange={(e) => onUpdate(field.key, Number(e.target.value))}
                    className="w-32 px-3 py-1.5 border border-slate-200 rounded-lg text-right font-mono focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 outline-none"
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

export default FinancialTable;

import React from 'react';
import { Company, FinancialStatement, Covenant } from '../types';

interface CovenantAlertsProps {
  company: Company;
  statement: FinancialStatement;
}

const CovenantAlerts: React.FC<CovenantAlertsProps> = ({ company, statement }) => {
  const calculateValue = (covenant: Covenant, data: FinancialStatement['data']) => {
    try {
      // Basic manual evaluation to avoid eval()
      const { 
        revenue, cogs, operatingExpenses, ebitda, interestExpense, 
        netIncome, currentAssets, currentLiabilities, totalDebt, totalAssets, equity 
      } = data;

      if (covenant.formula.includes('currentAssets / currentLiabilities')) {
        return currentAssets / (currentLiabilities || 1);
      }
      if (covenant.formula.includes('ebitda / interestExpense')) {
        return ebitda / (interestExpense || 1);
      }
      if (covenant.formula.includes('totalDebt / ebitda')) {
        return totalDebt / (ebitda || 1);
      }

      return 0;
    } catch (e) {
      return 0;
    }
  };

  const isPassing = (covenant: Covenant, value: number) => {
    switch (covenant.operator) {
      case 'gt': return value > covenant.threshold;
      case 'lt': return value < covenant.threshold;
      case 'gte': return value >= covenant.threshold;
      case 'lte': return value <= covenant.threshold;
      default: return false;
    }
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
      {company.covenants.map((covenant) => {
        const val = calculateValue(covenant, statement.data);
        const pass = isPassing(covenant, val);
        return (
          <div key={covenant.id} className={`p-6 rounded-2xl border ${pass ? 'border-emerald-200 bg-emerald-50/30' : 'border-rose-200 bg-rose-50/30'} flex flex-col`}>
            <div className="flex justify-between items-start mb-4">
              <div>
                <h4 className="font-bold text-slate-800">{covenant.name}</h4>
                <p className="text-xs text-slate-500">{covenant.description}</p>
              </div>
              <div className={`px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${pass ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                {pass ? 'Compliant' : 'Breach'}
              </div>
            </div>
            <div className="flex items-end justify-between mt-auto">
              <div>
                <span className="text-3xl font-black text-slate-900 font-mono">{val.toFixed(2)}</span>
                <span className="text-slate-400 text-sm ml-1 font-medium">Actual</span>
              </div>
              <div className="text-right">
                <span className="block text-xs text-slate-400 font-medium uppercase">Threshold</span>
                <span className="text-sm font-bold text-slate-700">{covenant.operator.toUpperCase()} {covenant.threshold}</span>
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default CovenantAlerts;

