import CovenantAlerts from './components/CovenantAlerts';
import { Company, AppRoute, FinancialStatement, ExtractionResult } from './types';
import { DEFAULT_COVENANTS } from './constants';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, AreaChart, Area } from 'recharts';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [tempExtraction, setTempExtraction] = useState<ExtractionResult | null>(null);
  const [isProcessingNew, setIsProcessingNew] = useState(false);

  // Load from LocalStorage
  useEffect(() => {
    const saved = localStorage.getItem('finanalyzer_data');
    if (saved) {
      setCompanies(JSON.parse(saved));
    } else {
      // Mock initial data
      const mockCompany: Company = {
        id: 'mock-1',
        name: 'Stellar Logistics Inc.',
        industry: 'Logistics',
        covenants: DEFAULT_COVENANTS,
        statements: [
          {
            id: 's1',
            companyId: 'mock-1',
            period: 'FY 2022',
            uploadDate: new Date().toISOString(),
            data: {
              revenue: 5200000, cogs: 3100000, operatingExpenses: 800000, ebitda: 1300000,
              interestExpense: 200000, netIncome: 1100000, currentAssets: 2100000,
              currentLiabilities: 1500000, totalDebt: 4500000, totalAssets: 8000000, equity: 3500000
            }
          },
          {
            id: 's2',
            companyId: 'mock-1',
            period: 'FY 2023',
            uploadDate: new Date().toISOString(),
            data: {
              revenue: 6100000, cogs: 3400000, operatingExpenses: 950000, ebitda: 1750000,
              interestExpense: 250000, netIncome: 1500000, currentAssets: 2800000,
              currentLiabilities: 1800000, totalDebt: 4000000, totalAssets: 9500000, equity: 5500000
            }
          }
        ]
      };
      setCompanies([mockCompany]);
    }
  }, []);

  useEffect(() => {
    if (companies.length > 0) {
      localStorage.setItem('finanalyzer_data', JSON.stringify(companies));
    }
  }, [companies]);

  const selectedCompany = companies.find(c => c.id === selectedCompanyId) || companies[0];

  const handleDataExtracted = (result: ExtractionResult) => {
    setTempExtraction(result);
    setIsProcessingNew(true);
  };

  const finalizeExtraction = () => {
    if (!tempExtraction) return;

    const newStatement: FinancialStatement = {
      id: Math.random().toString(36).substr(2, 9),
      companyId: selectedCompany.id,
      period: tempExtraction.period,
      uploadDate: new Date().toISOString(),
      data: tempExtraction.data
    };

    setCompanies(prev => prev.map(c => 
      c.id === selectedCompany.id 
        ? { ...c, statements: [...c.statements, newStatement].sort((a, b) => b.period.localeCompare(a.period)) }
        : c
    ));

    setTempExtraction(null);
    setIsProcessingNew(false);
  };

