import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult } from "../types";

const extractionSchema = {
  type: Type.OBJECT,
  properties: {
    period: { type: Type.STRING, description: "The reporting period, e.g., FY2023 or Q2 2024." },
    data: {
      type: Type.OBJECT,
      properties: {
        revenue: { type: Type.NUMBER },
        cogs: { type: Type.NUMBER },
        operatingExpenses: { type: Type.NUMBER },
        ebitda: { type: Type.NUMBER },
        interestExpense: { type: Type.NUMBER },
        netIncome: { type: Type.NUMBER },
        currentAssets: { type: Type.NUMBER },
        currentLiabilities: { type: Type.NUMBER },
        totalDebt: { type: Type.NUMBER },
        totalAssets: { type: Type.NUMBER },
        equity: { type: Type.NUMBER },
      },
      required: [
        "revenue", "cogs", "operatingExpenses", "ebitda", 
        "interestExpense", "netIncome", "currentAssets", 
        "currentLiabilities", "totalDebt", "totalAssets", "equity"
      ]
    }
  },
  required: ["period", "data"]
};

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    // Fixed: Always use process.env.API_KEY directly as a named parameter as per guidelines
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async extractFromImage(base64Data: string, mimeType: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: "Extract the financial figures from this statement. If a figure is not explicitly found, estimate it if possible based on other numbers or provide 0. Ensure the output is valid JSON matching the schema.",
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: extractionSchema,
      },
    });

    return JSON.parse(response.text || '{}') as ExtractionResult;
  }

  async extractFromText(text: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Extract the following financial data from this raw text or spreadsheet data: ${text}`,
      config: {
        responseMimeType: "application/json",
        responseSchema: extractionSchema,
      },
    });

    return JSON.parse(response.text || '{}') as ExtractionResult;
  }
}

export interface FinancialStatement {
  id: string;
  companyId: string;
  period: string; // e.g., "FY2023", "Q3 2024"
  uploadDate: string;
  data: {
    revenue: number;
    cogs: number;
    operatingExpenses: number;
    ebitda: number;
    interestExpense: number;
    netIncome: number;
    currentAssets: number;
    currentLiabilities: number;
    totalDebt: number;
    totalAssets: number;
    equity: number;
  };
}

export interface PaymentRecord {
  month: string;
  status: 'paid' | 'unpaid' | 'none';
}

export interface Covenant {
  id: string;
  name: string;
  formula: string;
  threshold: number;
  operator: 'gt' | 'lt' | 'gte' | 'lte';
  description: string;
}

export interface Company {
  id: string;
  name: string;
  industry: string;
  totalCreditValue: number;
  currentDue: number;
  defaultDays: number;
  defaultAmount: number;
  paymentHistory: PaymentRecord[];
  opinion: string;
  covenants: Covenant[];
  statements: FinancialStatement[];
}

export interface ExtractionResult {
  period: string;
  data: FinancialStatement['data'];
}

export enum AppRoute {
  DASHBOARD = 'dashboard',
  COMPANIES = 'companies',
  REPORT = 'report'
}

import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult, Company, FinancialStatement } from "../types";

const extractionSchema = {
  type: Type.OBJECT,
  properties: {
    period: { type: Type.STRING, description: "The reporting period, e.g., FY2023 or Q2 2024." },
    data: {
      type: Type.OBJECT,
      properties: {
        revenue: { type: Type.NUMBER },
        cogs: { type: Type.NUMBER },
        operatingExpenses: { type: Type.NUMBER },
        ebitda: { type: Type.NUMBER },
        interestExpense: { type: Type.NUMBER },
        netIncome: { type: Type.NUMBER },
        currentAssets: { type: Type.NUMBER },
        currentLiabilities: { type: Type.NUMBER },
        totalDebt: { type: Type.NUMBER },
        totalAssets: { type: Type.NUMBER },
        equity: { type: Type.NUMBER },
      },
      required: [
        "revenue", "cogs", "operatingExpenses", "ebitda", 
        "interestExpense", "netIncome", "currentAssets", 
        "currentLiabilities", "totalDebt", "totalAssets", "equity"
      ]
    }
  },
  required: ["period", "data"]
};

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async extractFromImage(base64Data: string, mimeType: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: "Extract the financial figures from this statement. Ensure the output is valid JSON matching the schema." }
        ],
      },
      config: { responseMimeType: "application/json", responseSchema: extractionSchema },
    });
    return JSON.parse(response.text || '{}') as ExtractionResult;
  }

  async extractFromText(text: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Extract the following financial data from this text: ${text}`,
      config: { responseMimeType: "application/json", responseSchema: extractionSchema },
    });
    return JSON.parse(response.text || '{}') as ExtractionResult;
  }

  async generateOpinion(company: Company, statement: FinancialStatement): Promise<string> {
    const prompt = `
      Act as a Senior Credit Analyst. Write a 2-3 paragraph professional opinion for the client "${company.name}".
      Financial Summary:
      - Revenue: ${statement.data.revenue}
      - EBITDA: ${statement.data.ebitda}
      - Total Debt: ${statement.data.totalDebt}
      - Leverage: ${(statement.data.totalDebt / statement.data.ebitda).toFixed(2)}
      - Current Dues: ${company.currentDue}
      - Defaults: ${company.defaultDays} days ($${company.defaultAmount})

      Discuss their creditworthiness, any covenant concerns, and payment behavior. Be concise and professional.
    `;
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Unable to generate opinion at this time.";
  }
}

