  companyId: string;
  period: string; // e.g., "FY2023", "Q3 2024"
  uploadDate: string;
  data: {
    revenue: number;
    cogs: number;
    operatingExpenses: number;
    ebitda: number;
    interestExpense: number;
    netIncome: number;
    currentAssets: number;
    currentLiabilities: number;
    totalDebt: number;
    totalAssets: number;
    equity: number;
  };
}

export interface PaymentRecord {
  month: string;
  principalStatus: 'paid' | 'unpaid' | 'none';
