        maxDefaultAmount: 12000,
        defaultFrequency12m: 2,
        paymentHistory: generateInitialHistory(),
        opinion: "MEMORANDUM\nTO: Credit Committee\nFROM: Analyst Team\nRE: ALPHA DYNAMICS CORP - Quarterly Review\n\nThe client currently exhibits strong operational margins...",
        covenants: DEFAULT_COVENANTS,
        statements: [
          {
            id: 's1',
            companyId: 'mock-1',
            period: 'Dec 2023',
            uploadDate: new Date().toISOString(),
            data: {
              revenue: 5200000, cogs: 3100000, operatingExpenses: 800000, ebitda: 1300000,
              interestExpense: 200000, netIncome: 1100000, currentAssets: 2100000,
              currentLiabilities: 1500000, totalDebt: 4500000, totalAssets: 8000000, equity: 3500000
            }
