          <div className="space-y-4">
            <div className="flex justify-between border-b border-slate-50 py-1">
              <span className="text-slate-400 text-xs uppercase font-bold">Total Credit Line</span>
              <span className="font-mono font-bold text-sm">${activeCompany.totalCreditValue.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-50 py-1">
              <span className="text-slate-400 text-xs uppercase font-bold">Outstanding Balance</span>
              <span className="font-mono font-bold text-sm">${activeCompany.currentDue.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-50 py-1">
              <span className="text-slate-400 text-xs uppercase font-bold">Default Frequency (12m)</span>
              <span className="font-mono font-bold text-sm">{activeCompany.defaultFrequency12m} Instances</span>
            </div>
             <div className="flex justify-between border-b border-slate-50 py-1">
              <span className="text-slate-400 text-xs uppercase font-bold">Max Past Due Amount</span>
              <span className="font-mono font-bold text-sm">${activeCompany.maxDefaultAmount.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-50 py-1">
              <span className="text-slate-400 text-xs uppercase font-bold">Max Past Due Duration</span>
              <span className="font-mono font-bold text-sm">{activeCompany.maxDefaultDays} Days</span>
            </div>
          </div>
        </section>

        <section>
          <h2 className="text-[10px] font-black text-slate-900 uppercase tracking-widest border-b-2 border-slate-900 mb-6 pb-1">6M Discipline Grid</h2>
          <div className="space-y-6">
            <div>
              <p className="text-[10px] font-bold text-indigo-600 uppercase mb-3">Principal Track</p>
              <div className="grid grid-cols-6 gap-2">
                {activeCompany.paymentHistory.map((p, i) => (
                  <div key={`rpt-p-${i}`} className="text-center">
                    <p className="text-[8px] text-slate-400 font-bold mb-1">{p.month}</p>
                    <div className="h-8 border border-slate-100 rounded flex items-center justify-center text-xs font-bold">
                      {p.principalStatus === 'paid' ? '✓' : p.principalStatus === 'unpaid' ? '✕' : '-'}
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <p className="text-[10px] font-bold text-amber-600 uppercase mb-3">Interest Track</p>
              <div className="grid grid-cols-6 gap-2">
                {activeCompany.paymentHistory.map((p, i) => (
                  <div key={`rpt-i-${i}`} className="text-center">
                    <p className="text-[8px] text-slate-400 font-bold mb-1">{p.month}</p>
                    <div className="h-8 border border-slate-100 rounded flex items-center justify-center text-xs font-bold">
                      {p.interestStatus === 'paid' ? '✓' : p.interestStatus === 'unpaid' ? '✕' : '-'}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </section>
      </div>

      <section className="mb-12">
        <h2 className="text-[10px] font-black text-slate-900 uppercase tracking-widest border-b-2 border-slate-900 mb-8 pb-1">Covenant Verification (Audit)</h2>
        {activeCompany.statements[0] ? (
          <CovenantAlerts company={activeCompany} statement={activeCompany.statements[0]} />
        ) : (
          <p className="text-xs text-slate-400 py-10 text-center border-2 border-dashed rounded-3xl">No financial statements uploaded for this period.</p>
        )}
      </section>

      <section className="bg-slate-50 p-10 rounded-3xl border border-slate-100">
        <h2 className="text-[10px] font-black text-slate-900 uppercase tracking-widest mb-6">Analyst Opinion & Credit Memo</h2>
        <div className="text-slate-700 leading-relaxed text-sm whitespace-pre-wrap font-serif italic border-l-4 border-slate-300 pl-6">
          {activeCompany.opinion || "Final analysis pending."}
        </div>
      </section>

      <div className="mt-32 pt-8 border-t-2 border-slate-900 text-[10px] text-slate-400 flex justify-between uppercase font-black tracking-widest">
        <span>© FinAnalyzer AI Audit System</span>
        <span className="text-slate-900">Signatory: _________________________</span>
        <span>Electronic Review Verified</span>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50 print:bg-white">
      <div className="print:hidden">
        <Sidebar currentRoute={route} onNavigate={setRoute} />
      </div>
      <main className={`flex-1 overflow-y-auto ${route === AppRoute.REPORT ? 'bg-slate-200 print:bg-white' : 'p-8 md:p-12'}`}>
        <div className={route === AppRoute.REPORT ? '' : 'max-w-7xl mx-auto'}>
          {route === AppRoute.DASHBOARD ? renderDashboard() : 
           route === AppRoute.COMPANIES ? renderCompanies() :
           renderReport()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import FileUpload from './components/FileUpload';
import FinancialTable from './components/FinancialTable';
import CovenantAlerts from './components/CovenantAlerts';
import { Company, AppRoute, FinancialStatement, ExtractionResult, PaymentRecord } from './types';
import { DEFAULT_COVENANTS, ICONS } from './constants';
import { GeminiService } from './services/geminiService';

const App: React.FC = () => {
  const [route, setRoute] = useState<AppRoute>(AppRoute.DASHBOARD);
  const [companies, setCompanies] = useState<Company[]>([]);
  const [selectedCompanyId, setSelectedCompanyId] = useState<string | null>(null);
  const [tempExtraction, setTempExtraction] = useState<ExtractionResult | null>(null);
  const [isProcessingNew, setIsProcessingNew] = useState(false);
  const [isAddingCompany, setIsAddingCompany] = useState(false);
  const [newCompanyName, setNewCompanyName] = useState('');
  const [isGeneratingOpinion, setIsGeneratingOpinion] = useState(false);

  const gemini = useMemo(() => new GeminiService(), []);

  // Helper to get last 6 months starting from a specific date or now
  const generateInitialHistory = (baseDate?: string): PaymentRecord[] => {
    const months = [];
    const date = baseDate ? new Date(baseDate) : new Date();
    for (let i = 0; i < 6; i++) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push({
        // Fix: Use '2-digit' instead of '2y' for the year option in toLocaleString to match Intl.DateTimeFormatOptions
        month: d.toLocaleString('default', { month: 'short', year: '2-digit' }),
        principalStatus: 'none' as const,
        interestStatus: 'none' as const,
      });
    }
    return months.reverse();
  };

  useEffect(() => {
    const saved = localStorage.getItem('finanalyzer_data_v3');
    if (saved) {
      setCompanies(JSON.parse(saved));
    } else {
      const mockCompany: Company = {
        id: 'mock-1',
        name: 'Alpha Dynamics Corp',
        industry: 'Manufacturing',
        totalCreditValue: 1500000,
        currentDue: 45000,
        defaultDays: 0,
        defaultAmount: 0,
        maxDefaultDays: 15,
        maxDefaultAmount: 12000,
        defaultFrequency12m: 2,
        paymentHistory: generateInitialHistory(),
        opinion: "MEMORANDUM\nTO: Credit Committee\nFROM: Analyst Team\nRE: ALPHA DYNAMICS CORP - Quarterly Review\n\nThe client currently exhibits strong operational margins...",
        covenants: DEFAULT_COVENANTS,
        statements: [
          {
            id: 's1',
            companyId: 'mock-1',
            period: 'Dec 2023',
            uploadDate: new Date().toISOString(),
            data: {
              revenue: 5200000, cogs: 3100000, operatingExpenses: 800000, ebitda: 1300000,
              interestExpense: 200000, netIncome: 1100000, currentAssets: 2100000,
              currentLiabilities: 1500000, totalDebt: 4500000, totalAssets: 8000000, equity: 3500000
            }
          }
        ]
      };
      setCompanies([mockCompany]);
      setSelectedCompanyId('mock-1');
    }
  }, []);

  useEffect(() => {
    if (companies.length > 0) {
      localStorage.setItem('finanalyzer_data_v3', JSON.stringify(companies));
    }
  }, [companies]);

  const activeCompany = useMemo(() => 
    companies.find(c => c.id === (selectedCompanyId || (companies[0]?.id))) || companies[0]
  , [companies, selectedCompanyId]);

  const updateActiveCompany = (updates: Partial<Company>) => {
    setCompanies(prev => prev.map(c => c.id === activeCompany.id ? { ...c, ...updates } : c));
  };

  const handleDataExtracted = (result: ExtractionResult) => {
    setTempExtraction(result);
    setIsProcessingNew(true);
  };

  const finalizeExtraction = () => {
    if (!tempExtraction) return;
    const newStatement: FinancialStatement = {
      id: Math.random().toString(36).substr(2, 9),
      companyId: activeCompany.id,
      period: tempExtraction.period,
      uploadDate: new Date().toISOString(),
      data: tempExtraction.data
    };

    // Update history dates if needed based on new statement
    const newHistory = activeCompany.statements.length === 0 ? generateInitialHistory(newStatement.period) : activeCompany.paymentHistory;

    setCompanies(prev => prev.map(c => 
      c.id === activeCompany.id 
        ? { 
            ...c, 
            paymentHistory: newHistory,
            statements: [newStatement, ...c.statements].sort((a,b) => b.period.localeCompare(a.period)) 
          }
        : c
    ));
    setTempExtraction(null);
    setIsProcessingNew(false);
  };

  const handleAddCompany = () => {
    if (!newCompanyName.trim()) return;
    const newCo: Company = {
      id: Math.random().toString(36).substr(2, 9),
      name: newCompanyName,
      industry: "Sector Unknown",
      totalCreditValue: 0,
      currentDue: 0,
      defaultDays: 0,
      defaultAmount: 0,
      maxDefaultDays: 0,
      maxDefaultAmount: 0,
      defaultFrequency12m: 0,
      paymentHistory: generateInitialHistory(),
      opinion: "",
      covenants: DEFAULT_COVENANTS,
      statements: []
    };
    setCompanies(prev => [...prev, newCo]);
    setSelectedCompanyId(newCo.id);
    setIsAddingCompany(false);
    setNewCompanyName('');
  };

  const generateAIOpinion = async () => {
    if (!activeCompany.statements.length) return;
    setIsGeneratingOpinion(true);
    try {
      const op = await gemini.generateOpinion(activeCompany, activeCompany.statements[0]);
      updateActiveCompany({ opinion: op });
    } finally {
      setIsGeneratingOpinion(false);
    }
  };

  const togglePayment = (index: number, field: 'principalStatus' | 'interestStatus') => {
    const history = [...activeCompany.paymentHistory];
    const current = history[index][field];
    const next = current === 'paid' ? 'unpaid' : (current === 'unpaid' ? 'none' : 'paid');
    history[index][field] = next;
    updateActiveCompany({ paymentHistory: history });
  };

  const renderDashboard = () => {
    if (!activeCompany) return <div className="p-10 text-center text-slate-400">Loading profile...</div>;

    return (
      <div className="space-y-8 animate-in fade-in duration-500 pb-20">
        <header className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tight">{activeCompany.name}</h1>
            <p className="text-slate-500 font-medium">Credit Portfolio Management • {activeCompany.industry}</p>
          </div>
          <div className="flex gap-3">
            <select 
              value={activeCompany.id} 
              onChange={(e) => setSelectedCompanyId(e.target.value)}
              className="bg-white border border-slate-200 px-4 py-2.5 rounded-xl font-semibold text-slate-700 shadow-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            >
              {companies.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
            <button onClick={() => setRoute(AppRoute.REPORT)} className="bg-slate-900 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-black transition-all">Export Memo</button>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-8">
            {/* Credit Entry Section */}
            <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
                <ICONS.Alert /> Credit Exposure & Default Metrics
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Total Credit Value ($)</label>
                  <input type="number" value={activeCompany.totalCreditValue} onChange={e => updateActiveCompany({ totalCreditValue: Number(e.target.value) })} className="w-full px-4 py-2 border rounded-xl font-mono text-sm" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Current Due ($)</label>
                  <input type="number" value={activeCompany.currentDue} onChange={e => updateActiveCompany({ currentDue: Number(e.target.value) })} className="w-full px-4 py-2 border rounded-xl font-mono text-sm" />
                </div>
                <div className="md:col-span-1"></div>

                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Max Default Days</label>
                  <input type="number" value={activeCompany.maxDefaultDays} onChange={e => updateActiveCompany({ maxDefaultDays: Number(e.target.value) })} className="w-full px-4 py-2 border rounded-xl font-mono text-sm" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Max Default Amount ($)</label>
                  <input type="number" value={activeCompany.maxDefaultAmount} onChange={e => updateActiveCompany({ maxDefaultAmount: Number(e.target.value) })} className="w-full px-4 py-2 border rounded-xl font-mono text-sm" />
                </div>
                <div>
                  <label className="block text-xs font-bold text-slate-400 uppercase mb-2">Freq. (Last 12m)</label>
                  <input type="number" value={activeCompany.defaultFrequency12m} onChange={e => updateActiveCompany({ defaultFrequency12m: Number(e.target.value) })} className="w-full px-4 py-2 border rounded-xl font-mono text-sm" />
                </div>
              </div>
            </div>

            {/* Dual Track Payment Tracker */}
            <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
              <h3 className="text-lg font-bold text-slate-800 mb-2">6-Month Payment Performance</h3>
              <p className="text-xs text-slate-400 mb-6">Track Principal & Interest separately. Start: Most recent statement date.</p>

              <div className="space-y-8">
                <div>
                  <h4 className="text-[10px] font-black uppercase text-indigo-600 tracking-widest mb-4">Principal Repayment</h4>
                  <div className="flex gap-3">
                    {activeCompany.paymentHistory.map((p, i) => (
                      <div key={`p-${i}`} className="flex-1 text-center">
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-2">{p.month}</p>
                        <button 
                          onClick={() => togglePayment(i, 'principalStatus')}
                          className={`w-full h-12 rounded-xl flex items-center justify-center text-lg transition-all border-2 ${
                            p.principalStatus === 'paid' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' :
                            p.principalStatus === 'unpaid' ? 'bg-rose-50 border-rose-200 text-rose-600' :
                            'bg-slate-50 border-slate-100 text-slate-200'
                          }`}
                        >
                          {p.principalStatus === 'paid' ? '✓' : p.principalStatus === 'unpaid' ? '✕' : ''}
                        </button>
                      </div>
                    ))}
                  </div>
                </div>

                <div>
                  <h4 className="text-[10px] font-black uppercase text-amber-600 tracking-widest mb-4">Interest Payment</h4>
                  <div className="flex gap-3">
                    {activeCompany.paymentHistory.map((p, i) => (
                      <div key={`i-${i}`} className="flex-1 text-center">
                        <p className="text-[10px] font-bold text-slate-400 uppercase mb-2">{p.month}</p>
                        <button 
                          onClick={() => togglePayment(i, 'interestStatus')}
                          className={`w-full h-12 rounded-xl flex items-center justify-center text-lg transition-all border-2 ${
                            p.interestStatus === 'paid' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' :
                            p.interestStatus === 'unpaid' ? 'bg-rose-50 border-rose-200 text-rose-600' :
                            'bg-slate-50 border-slate-100 text-slate-200'
                          }`}
                        >
                          {p.interestStatus === 'paid' ? '✓' : p.interestStatus === 'unpaid' ? '✕' : ''}
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            {/* AI Memo Opinion */}
            <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-lg font-bold text-slate-800">Credit Memo Opinion</h3>
                  <p className="text-xs text-slate-400">Review covenant standing and risk assessment.</p>
                </div>
                <button 
                  disabled={isGeneratingOpinion || !activeCompany.statements.length}
                  onClick={generateAIOpinion}
                  className="bg-indigo-50 text-indigo-600 px-4 py-2 rounded-xl text-xs font-bold hover:bg-indigo-100 disabled:opacity-50 flex items-center gap-2"
                >
                  <ICONS.Dashboard /> {isGeneratingOpinion ? 'Drafting Memo...' : 'Generate Memo Draft'}
                </button>
              </div>
              <textarea 
                value={activeCompany.opinion}
                onChange={e => updateActiveCompany({ opinion: e.target.value })}
                placeholder="Professional credit opinion..."
                className="w-full h-64 px-5 py-5 border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-slate-700 leading-relaxed font-mono text-sm"
              />
            </div>
          </div>

          <div className="space-y-8">
            <FileUpload onDataExtracted={handleDataExtracted} />
            <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
              <div className="flex justify-between items-center mb-6">
                <h3 className="text-lg font-bold text-slate-800">Covenants</h3>
                <span className="text-[10px] bg-indigo-50 text-indigo-700 px-2 py-1 rounded-md font-bold uppercase tracking-wider">LTM Basis</span>
              </div>
              {activeCompany.statements.length > 0 ? (
                <div className="space-y-4">
                  {activeCompany.covenants.map(c => (
                    <div key={c.id} className="p-4 rounded-xl bg-slate-50 border border-slate-100">
                      <div className="flex justify-between items-center mb-1">
                        <span className="text-sm font-bold text-slate-700">{c.name}</span>
                        <span className="text-xs font-mono text-slate-400">{c.operator.toUpperCase()} {c.threshold}</span>
                      </div>
                      <p className="text-[10px] text-slate-400 leading-relaxed">{c.description}</p>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-8">
                  <div className="text-slate-300 mb-2 flex justify-center"><ICONS.Upload /></div>
                  <p className="text-xs text-slate-400">Upload data to trigger audit.</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Profile Creation Modal */}
        {isAddingCompany && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
            <div className="bg-white rounded-3xl w-full max-w-md p-8 shadow-2xl animate-in zoom-in-95 duration-200">
              <h2 className="text-2xl font-black text-slate-900 mb-2">Create Profile</h2>
              <p className="text-slate-500 mb-6 text-sm">Initialize a new financial entity for historical monitoring.</p>
              <input 
                autoFocus
                type="text" 
                placeholder="Full Entity Name" 
                value={newCompanyName}
                onChange={e => setNewCompanyName(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && handleAddCompany()}
                className="w-full px-4 py-3 border border-slate-200 rounded-xl mb-6 outline-none focus:ring-2 focus:ring-indigo-500 font-medium"
              />
              <div className="flex gap-3">
                <button onClick={() => setIsAddingCompany(false)} className="flex-1 py-3 text-slate-600 font-bold hover:bg-slate-100 rounded-xl transition-all">Cancel</button>
                <button onClick={handleAddCompany} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-bold hover:bg-indigo-700 transition-all">Save Profile</button>
              </div>
            </div>
          </div>
        )}

        {/* Extraction Modal */}
        {isProcessingNew && tempExtraction && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
            <div className="bg-white rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
              <div className="p-6 border-b flex justify-between items-center bg-slate-50">
                <div>
                  <h2 className="text-xl font-bold">AI Extraction Audit</h2>
                  <p className="text-sm text-slate-500 font-mono">{tempExtraction.period}</p>
                </div>
                <div className="flex gap-3">
                  <button onClick={() => setIsProcessingNew(false)} className="px-5 py-2 text-slate-600 font-bold hover:bg-slate-100 rounded-xl">Discard</button>
                  <button onClick={finalizeExtraction} className="bg-indigo-600 text-white px-8 py-2 rounded-xl font-bold hover:bg-indigo-700">Audit Complete</button>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto p-8">
                <FinancialTable 
                  data={tempExtraction.data} 
                  onUpdate={(field, val) => setTempExtraction({ ...tempExtraction, data: { ...tempExtraction.data, [field]: val }})} 
                />
              </div>
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderCompanies = () => (
    <div className="space-y-8">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight">Financial Profiles</h1>
          <p className="text-slate-500 font-medium">Monitoring {companies.length} active credit files</p>
        </div>
        <button onClick={() => setIsAddingCompany(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-xl font-bold shadow-md hover:bg-indigo-700 transition-all">+ Add Profile</button>
      </header>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {companies.map(co => (
          <div key={co.id} className="bg-white border border-slate-200 p-8 rounded-3xl hover:border-indigo-300 transition-all group cursor-pointer" onClick={() => { setSelectedCompanyId(co.id); setRoute(AppRoute.DASHBOARD); }}>
             <div className="flex justify-between items-start mb-6">
              <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-500 transition-colors">
                <ICONS.Companies />
              </div>
              <div className={`px-2 py-1 rounded-md text-[10px] font-bold uppercase ${co.defaultFrequency12m > 0 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                {co.defaultFrequency12m > 0 ? `${co.defaultFrequency12m} Defaults` : 'Stable'}
              </div>
            </div>
            <h3 className="text-xl font-bold text-slate-900 mb-1">{co.name}</h3>
            <p className="text-slate-500 text-sm mb-6">{co.industry}</p>
            <div className="flex justify-between items-end border-t border-slate-100 pt-4">
              <div>
                <span className="text-[10px] font-bold text-slate-400 uppercase block">Limit</span>
                <span className="text-sm font-black text-slate-700 font-mono">${(co.totalCreditValue / 1000).toFixed(0)}k</span>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-bold text-slate-400 uppercase block">Hist. Breach</span>
                <span className="text-sm font-black text-rose-600 font-mono">{co.maxDefaultDays}d</span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
