import { GoogleGenAI, Type } from "@google/genai";
import { ExtractionResult, Company, FinancialStatement } from "../types";

const extractionSchema = {
  type: Type.OBJECT,
  properties: {
    period: { type: Type.STRING, description: "The reporting period, e.g., FY2023 or Q2 2024." },
    data: {
      type: Type.OBJECT,
      properties: {
        revenue: { type: Type.NUMBER },
        cogs: { type: Type.NUMBER },
        operatingExpenses: { type: Type.NUMBER },
        ebitda: { type: Type.NUMBER },
        interestExpense: { type: Type.NUMBER },
        netIncome: { type: Type.NUMBER },
        currentAssets: { type: Type.NUMBER },
        currentLiabilities: { type: Type.NUMBER },
        totalDebt: { type: Type.NUMBER },
        totalAssets: { type: Type.NUMBER },
        equity: { type: Type.NUMBER },
      },
      required: [
        "revenue", "cogs", "operatingExpenses", "ebitda", 
        "interestExpense", "netIncome", "currentAssets", 
        "currentLiabilities", "totalDebt", "totalAssets", "equity"
      ]
    }
  },
  required: ["period", "data"]
};

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async extractFromImage(base64Data: string, mimeType: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: "Extract the financial figures from this statement. Ensure the output is valid JSON matching the schema." }
        ],
      },
      config: { responseMimeType: "application/json", responseSchema: extractionSchema },
    });
    return JSON.parse(response.text || '{}') as ExtractionResult;
  }

  async extractFromText(text: string): Promise<ExtractionResult> {
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Extract the following financial data from this text: ${text}`,
      config: { responseMimeType: "application/json", responseSchema: extractionSchema },
    });
    return JSON.parse(response.text || '{}') as ExtractionResult;
  }

  async generateOpinion(company: Company, statement: FinancialStatement): Promise<string> {
    const prompt = `
      Act as a Senior Financial Risk Analyst. Write a summary of the credit standing for "${company.name}" in the format of a professional email.

      Focus strictly on:
      1. Covenant Compliance Summary (Based on the data below).
      2. Key Financial Indicators (Leverage, DSCR).
      3. Summary of payment behavior and default metrics.

      Financial Context:
      - Period: ${statement.period}
      - Leverage: ${(statement.data.totalDebt / statement.data.ebitda).toFixed(2)}x
      - DSCR: ${(statement.data.ebitda / statement.data.interestExpense).toFixed(2)}x
      - Current Credit Exposure: $${company.totalCreditValue}
      - Max Defaults: $${company.maxDefaultAmount} (${company.maxDefaultDays} days)
      - Default Occurrences (12m): ${company.defaultFrequency12m} times.

      Tone: Professional, succinct, "like a mail". Start with "Dear Credit Team," or similar.
    `;
    const response = await this.ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Summary analysis not available.";
  }
}

import React, { useState, useRef } from 'react';
import { GeminiService } from '../services/geminiService';
import { ExtractionResult } from '../types';
import { ICONS } from '../constants';

interface FileUploadProps {
  onDataExtracted: (result: ExtractionResult) => void;
}

const FileUpload: React.FC<FileUploadProps> = ({ onDataExtracted }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const gemini = new GeminiService();

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    setError(null);

    try {
      if (file.type.startsWith('image/')) {
        const reader = new FileReader();
        reader.onload = async () => {
          const base64 = (reader.result as string).split(',')[1];
          const result = await gemini.extractFromImage(base64, file.type);
          onDataExtracted(result);
          setIsUploading(false);
        };
        reader.readAsDataURL(file);
      } else if (file.type === 'application/pdf') {
        const arrayBuffer = await file.arrayBuffer();
        const pdf = await (window as any).pdfjsLib.getDocument({ data: arrayBuffer }).promise;
        const page = await pdf.getPage(1);
        const viewport = page.getViewport({ scale: 2 });
        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');
        canvas.height = viewport.height;
        canvas.width = viewport.width;
        await page.render({ canvasContext: context, viewport: viewport }).promise;
        const base64 = canvas.toDataURL('image/jpeg').split(',')[1];
        const result = await gemini.extractFromImage(base64, 'image/jpeg');
        onDataExtracted(result);
        setIsUploading(false);
      } else if (file.name.endsWith('.xlsx') || file.name.endsWith('.xls') || file.name.endsWith('.csv')) {
        const arrayBuffer = await file.arrayBuffer();
        const workbook = (window as any).XLSX.read(arrayBuffer, { type: 'array' });
        const firstSheet = workbook.Sheets[workbook.SheetNames[0]];
        const json = (window as any).XLSX.utils.sheet_to_json(firstSheet);
        const result = await gemini.extractFromText(JSON.stringify(json));
        onDataExtracted(result);
        setIsUploading(false);
      } else {
        setError("Please upload a PDF, Image, or Excel file.");
        setIsUploading(false);
      }
    } catch (err) {
      console.error(err);
      setError("Failed to extract data. Ensure document clarity.");
      setIsUploading(false);
    }
  };

  return (
    <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-8 transition-all hover:border-indigo-300">
      <div className="flex flex-col items-center justify-center text-center space-y-4">
        <div className={`w-16 h-16 rounded-full flex items-center justify-center ${isUploading ? 'bg-indigo-100 text-indigo-600 animate-pulse' : 'bg-slate-100 text-slate-400'}`}>
          <ICONS.Upload />
        </div>
        <div>
          <h3 className="text-lg font-bold text-slate-800">Upload Source Document</h3>
          <p className="text-slate-500 max-w-sm mt-1 text-sm">
            Excel (.xlsx), PDF, or Images (PNG, JPG). Gemini AI will identify the financial model.
          </p>
        </div>
        <input
          type="file"
          className="hidden"
          ref={fileInputRef}
          onChange={handleFileChange}
          accept="image/*, application/pdf, .xlsx, .xls, .csv"
        />
        <button
          disabled={isUploading}
          onClick={() => fileInputRef.current?.click()}
          className={`px-6 py-2.5 rounded-xl font-semibold transition-all shadow-md ${
            isUploading 
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
              : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95'
          }`}
        >
          {isUploading ? 'Gemini is Analyzing...' : 'Choose File'}
        </button>
        {error && <p className="text-red-500 text-xs font-bold mt-2 uppercase">{error}</p>}
      </div>
    </div>
  );
};

export default FileUpload;

