                          onClick={() => togglePayment(i, 'principalStatus')}
                          className={`w-full h-14 rounded-2xl flex items-center justify-center text-xl transition-all border-2 ${
                            p.principalStatus === 'paid' ? 'bg-emerald-50 border-emerald-200 text-emerald-600 shadow-sm' :
                            p.principalStatus === 'unpaid' ? 'bg-rose-50 border-rose-200 text-rose-600 shadow-sm' :
                            'bg-slate-50 border-slate-100 text-slate-200 hover:border-slate-300'
                          }`}
                        >
                          {p.principalStatus === 'paid' ? '✓' : p.principalStatus === 'unpaid' ? '✕' : ''}
                        </button>
                      </div>
                    ))}
                  </div>
                </div>

                <div>
                  <h4 className="text-[10px] font-black uppercase text-amber-500 tracking-tighter mb-4">Interest Track</h4>
                  <div className="grid grid-cols-6 gap-3">
                    {activeCompany.paymentHistory.map((p, i) => (
                      <div key={`i-${i}`} className="text-center group">
                        <p className="text-[10px] font-bold text-slate-400 mb-2">{p.month}</p>
                        <button 
                          onClick={() => togglePayment(i, 'interestStatus')}
                          className={`w-full h-14 rounded-2xl flex items-center justify-center text-xl transition-all border-2 ${
                            p.interestStatus === 'paid' ? 'bg-emerald-50 border-emerald-200 text-emerald-600 shadow-sm' :
                            p.interestStatus === 'unpaid' ? 'bg-rose-50 border-rose-200 text-rose-600 shadow-sm' :
                            'bg-slate-50 border-slate-100 text-slate-200 hover:border-slate-300'
                          }`}
                        >
                          {p.interestStatus === 'paid' ? '✓' : p.interestStatus === 'unpaid' ? '✕' : ''}
                        </button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>

            {/* AI Summary Opinion - Mail Style */}
            <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative">
              <div className="absolute top-0 left-0 w-2 h-full bg-slate-800"></div>
              <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-xl font-bold text-slate-800">Analyst Covenant Summary</h3>
                  <p className="text-xs text-slate-400 font-medium italic mt-1">AI-generated mail-style summary of the client's credit status.</p>
                </div>
                <button 
                  disabled={isGeneratingOpinion || !activeCompany.statements.length}
                  onClick={generateMailOpinion}
                  className="bg-indigo-600 text-white px-5 py-2.5 rounded-xl text-xs font-bold shadow-lg shadow-indigo-100 active:scale-95 disabled:opacity-50 transition-all"
                >
                  {isGeneratingOpinion ? 'AI is Writing...' : 'Write Mail Summary'}
                </button>
              </div>
              <textarea 
                value={activeCompany.opinion}
                onChange={e => updateActiveCompany({ opinion: e.target.value })}
                placeholder="The credit summary email will appear here after generation..."
                className="w-full h-80 px-6 py-6 border border-slate-200 rounded-[1.5rem] focus:ring-2 focus:ring-indigo-500 outline-none resize-none text-slate-700 leading-relaxed font-mono text-xs whitespace-pre-wrap bg-slate-50/50"
              />
            </div>
          </div>

          <div className="space-y-8">
            <FileUpload onDataExtracted={handleDataExtracted} />
            <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative">
              <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center justify-between">
                <span>Covenants Status</span>
                {activeCompany.statements.length > 0 && <span className="text-[10px] font-black text-indigo-600 uppercase">Live Audit</span>}
              </h3>
              {activeCompany.statements.length > 0 ? (
                <div className="space-y-4">
                  {activeCompany.covenants.map(c => (
                    <div key={c.id} className="p-4 rounded-2xl bg-slate-50 border border-slate-100 group transition-all hover:bg-white hover:shadow-md">
                      <div className="flex justify-between items-center mb-1">
                        <span className="text-sm font-bold text-slate-800">{c.name}</span>
                        <span className="text-[10px] font-mono text-slate-400 font-bold">{c.operator.toUpperCase()} {c.threshold}</span>
                      </div>
                      <p className="text-[10px] text-slate-400 font-medium leading-relaxed">{c.description}</p>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="text-center py-10 opacity-30">
                   <div className="flex justify-center mb-2"><ICONS.Upload /></div>
                   <p className="text-xs font-bold uppercase tracking-widest">No Statements</p>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Profile Creation Dialog */}
        {isAddingCompany && (
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6">
            <div className="bg-white rounded-[2.5rem] w-full max-w-md p-10 shadow-2xl animate-in zoom-in-95 duration-200">
              <h2 className="text-3xl font-black text-slate-900 mb-2">New Entity</h2>
              <p className="text-slate-500 mb-8 font-medium">Add a new company profile to your portfolio.</p>
              <div className="space-y-6">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Company Full Legal Name</label>
                  <input 
                    autoFocus
                    type="text" 
                    placeholder="Enter name..." 
                    value={newCompanyName}
                    onChange={e => setNewCompanyName(e.target.value)}
                    onKeyDown={e => e.key === 'Enter' && handleAddCompany()}
                    className="w-full px-5 py-4 bg-slate-50 border-none rounded-2xl outline-none ring-2 ring-slate-100 focus:ring-4 focus:ring-indigo-500/10 font-bold transition-all"
                  />
                </div>
              </div>
              <div className="flex gap-4 mt-10">
                <button onClick={() => setIsAddingCompany(false)} className="flex-1 py-4 text-slate-500 font-bold hover:bg-slate-50 rounded-2xl transition-all">Cancel</button>
                <button onClick={handleAddCompany} className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-bold hover:bg-indigo-700 shadow-xl shadow-indigo-100 active:scale-95 transition-all">Create Profile</button>
              </div>
            </div>
          </div>
        )}

        {/* AI Audit Review Modal */}
        {isProcessingNew && tempExtraction && (
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
            <div className="bg-white rounded-[2.5rem] w-full max-w-5xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
              <div className="p-8 border-b flex justify-between items-center bg-slate-50/50">
                <div>
                  <h2 className="text-2xl font-black text-slate-900">AI Audit & Verification</h2>
                  <p className="text-sm text-slate-500 font-bold font-mono mt-1 uppercase">Period Identified: {tempExtraction.period}</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setIsProcessingNew(false)} className="px-6 py-3 text-slate-500 font-bold hover:bg-slate-100 rounded-2xl">Discard</button>
                  <button onClick={finalizeExtraction} className="bg-indigo-600 text-white px-10 py-3 rounded-2xl font-bold hover:bg-indigo-700 shadow-xl shadow-indigo-100">Confirm Audit</button>
                </div>
              </div>
              <div className="flex-1 overflow-y-auto p-10">
                <FinancialTable 
                  data={tempExtraction.data} 
                  onUpdate={(field, val) => setTempExtraction({ ...tempExtraction, data: { ...tempExtraction.data, [field]: val }})} 
                />
              </div>
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderCompanies = () => (
    <div className="space-y-10">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tight">Financial Portfolio</h1>
          <p className="text-slate-500 font-medium">Managing {companies.length} monitoring profiles</p>
        </div>
        <button onClick={() => setIsAddingCompany(true)} className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all">+ Add Profile</button>
      </header>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {companies.map(co => (
          <div key={co.id} className="bg-white border border-slate-200 p-10 rounded-[2.5rem] hover:border-indigo-400 transition-all group cursor-pointer shadow-sm hover:shadow-xl" onClick={() => { setSelectedCompanyId(co.id); setRoute(AppRoute.DASHBOARD); }}>
             <div className="flex justify-between items-start mb-8">
              <div className="w-14 h-14 bg-slate-50 rounded-[1.25rem] flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                <ICONS.Companies />
              </div>
              <div className={`px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest ${co.defaultFrequency12m > 0 ? 'bg-rose-100 text-rose-700' : 'bg-emerald-100 text-emerald-700'}`}>
                {co.defaultFrequency12m > 0 ? `${co.defaultFrequency12m} Defaults` : 'Compliant'}
              </div>
            </div>
            <h3 className="text-2xl font-black text-slate-900 mb-1 leading-tight">{co.name}</h3>
            <p className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-8">{co.industry}</p>
            <div className="grid grid-cols-2 gap-4 border-t border-slate-50 pt-6">
              <div>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Credit Limit</span>
                <span className="text-lg font-black text-slate-800 font-mono">${(co.totalCreditValue / 1000).toFixed(0)}k</span>
              </div>
              <div className="text-right">
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-1">Risk Rating</span>
                <span className={`text-lg font-black font-mono ${co.maxDefaultDays > 30 ? 'text-rose-600' : 'text-emerald-600'}`}>
                   {co.maxDefaultDays > 30 ? 'Critical' : 'Stable'}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderReport = () => (
    <div className="bg-white min-h-screen p-20 max-w-6xl mx-auto shadow-2xl rounded-[3rem] my-10 print:shadow-none print:my-0 print:p-10">
      <div className="flex justify-between items-start border-b-8 border-slate-900 pb-10 mb-16">
        <div>
          <h1 className="text-4xl font-black text-slate-900 tracking-tighter uppercase mb-2">{activeCompany.name}</h1>
          <p className="text-slate-400 font-black uppercase tracking-widest text-[11px]">Comprehensive Credit Assessment & Covenant Audit</p>
        </div>
        <div className="text-right font-mono text-[10px] font-bold">
          <p className="bg-slate-100 px-3 py-1 rounded-full inline-block">ID: {activeCompany.id.toUpperCase()}</p>
          <p className="mt-2 text-slate-400">ISSUED: {new Date().toLocaleDateString().toUpperCase()}</p>
          <div className="flex gap-2 mt-6 print:hidden">
            <button onClick={() => window.print()} className="bg-slate-900 text-white px-5 py-2 rounded-xl font-bold uppercase text-[10px] shadow-lg active:scale-95 transition-all">Save as PDF</button>
            <button onClick={() => setRoute(AppRoute.DASHBOARD)} className="bg-slate-100 text-slate-600 px-5 py-2 rounded-xl font-bold uppercase text-[10px] hover:bg-slate-200 transition-all">Close</button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-20 mb-16">
        <section>
          <h2 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] border-b-2 border-slate-900 mb-8 pb-1">Exposure Profile</h2>
          <div className="space-y-6">
            <div className="flex justify-between border-b border-slate-50 py-1.5">
              <span className="text-slate-400 text-xs uppercase font-black">Authorized Credit Line</span>
              <span className="font-mono font-black text-base text-slate-900">${activeCompany.totalCreditValue.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-50 py-1.5">
              <span className="text-slate-400 text-xs uppercase font-black">Current Utilized Balance</span>
              <span className="font-mono font-black text-base text-rose-600">${activeCompany.currentDue.toLocaleString()}</span>
            </div>
             <div className="flex justify-between border-b border-slate-50 py-1.5">
              <span className="text-slate-400 text-xs uppercase font-black">Peak Default Amount</span>
              <span className="font-mono font-black text-base text-slate-900">${activeCompany.maxDefaultAmount.toLocaleString()}</span>
            </div>
            <div className="flex justify-between border-b border-slate-50 py-1.5">
              <span className="text-slate-400 text-xs uppercase font-black">Historical Overdue Breach</span>
              <span className="font-mono font-black text-base text-slate-900">{activeCompany.maxDefaultDays} Continuous Days</span>
            </div>
          </div>
        </section>

        <section>
          <h2 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] border-b-2 border-slate-900 mb-8 pb-1">Repayment Performance (6M)</h2>
          <div className="space-y-10">
            <div>
              <p className="text-[9px] font-black text-indigo-500 uppercase mb-3 tracking-widest">Principal Repayment Track</p>
              <div className="grid grid-cols-6 gap-2">
                {activeCompany.paymentHistory.map((p, i) => (
                  <div key={`rpt-p-${i}`} className="text-center">
                    <p className="text-[9px] text-slate-400 font-black mb-1.5">{p.month}</p>
                    <div className={`h-10 border rounded-xl flex items-center justify-center text-xs font-black ${p.principalStatus === 'paid' ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : p.principalStatus === 'unpaid' ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-slate-50 border-slate-50 text-slate-200'}`}>
                      {p.principalStatus === 'paid' ? '✓' : p.principalStatus === 'unpaid' ? '✕' : '-'}
                    </div>
                  </div>
                ))}
              </div>
            </div>
            <div>
              <p className="text-[9px] font-black text-amber-500 uppercase mb-3 tracking-widest">Interest Payment Track</p>
              <div className="grid grid-cols-6 gap-2">
                {activeCompany.paymentHistory.map((p, i) => (
                  <div key={`rpt-i-${i}`} className="text-center">
                    <p className="text-[9px] text-slate-400 font-black mb-1.5">{p.month}</p>
                    <div className={`h-10 border rounded-xl flex items-center justify-center text-xs font-black ${p.interestStatus === 'paid' ? 'bg-emerald-50 border-emerald-100 text-emerald-600' : p.interestStatus === 'unpaid' ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-slate-50 border-slate-50 text-slate-200'}`}>
                      {p.interestStatus === 'paid' ? '✓' : p.interestStatus === 'unpaid' ? '✕' : '-'}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </section>
      </div>

      <section className="mb-20">
        <h2 className="text-[11px] font-black text-slate-900 uppercase tracking-[0.2em] border-b-2 border-slate-900 mb-10 pb-1">Covenant Compliance Audit</h2>
        {activeCompany.statements[0] ? (
          <CovenantAlerts company={activeCompany} statement={activeCompany.statements[0]} />
        ) : (
          <div className="py-16 text-center border-4 border-dashed border-slate-50 rounded-[2rem] text-slate-300 font-black uppercase text-xs tracking-widest">
            Audit Data Pending Financial Statement Upload
          </div>
        )}
      </section>

      <section className="bg-slate-900 p-16 rounded-[3rem] text-white">
        <h2 className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.2em] mb-10 text-center">Analyst Covenant Summary (Mail Style)</h2>
        <div className="text-slate-300 leading-relaxed text-sm whitespace-pre-wrap font-mono border-l-2 border-slate-700 pl-8 ml-4">
          {activeCompany.opinion || "Final Credit Review Summary Pending Analyst Sign-off."}
        </div>
      </section>

      <div className="mt-40 pt-10 border-t-4 border-slate-900 text-[11px] text-slate-400 flex justify-between uppercase font-black tracking-widest">
        <span>Generated by FinAnalyzer AI Professional</span>
        <span className="text-slate-900">Signatory: __________________________________</span>
        <span>Electronic Audit Hash: {Math.random().toString(16).substring(2, 10).toUpperCase()}</span>
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-slate-50 print:bg-white overflow-hidden">
      <div className="print:hidden">
        <Sidebar currentRoute={route} onNavigate={setRoute} />
      </div>
      <main className={`flex-1 overflow-y-auto ${route === AppRoute.REPORT ? 'bg-slate-200 print:bg-white' : 'p-8 md:p-12'}`}>
        <div className={route === AppRoute.REPORT ? '' : 'max-w-7xl mx-auto'}>
          {route === AppRoute.DASHBOARD ? renderDashboard() : 
           route === AppRoute.COMPANIES ? renderCompanies() :
           renderReport()}
        </div>
      </main>
    </div>
  );
};

export default App;

