             className="w-full bg-white/10 hover:bg-white/20 text-white py-3 rounded-xl text-xs font-black uppercase transition-all"
           >
             Sync Data
           </button>
        </div>
      </div>

      <div className="px-8 py-6 border-t border-slate-50 flex items-center gap-3">
         <div className="w-8 h-8 rounded-full bg-indigo-50 border border-indigo-100 flex items-center justify-center text-indigo-600 font-black text-[10px]">AI</div>
         <div>
            <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest leading-none">Model Running</p>
            <p className="text-xs font-bold text-slate-900">Gemini 3 Flash</p>
         </div>
      </div>
    </aside>
  );
};

export default Sidebar;
